INSERT INTO config (config_key, config_value, language_code, guild_id) VALUES
('txtOnboardingDay1', 'Hey there! Thanks for installing Round Robin StoryBot in your server. It looks like it hasn''t been configured yet; running `/storyadmin setup` will get you started, and it only takes a minute. If you run into any trouble or have questions, come say hi in the Hub server: [hubInviteUrl]. Happy writing!\n~Shantismurf', 'en', 1),
('txtOnboardingDay7', 'Hi again! This is just a friendly nudge: Round Robin StoryBot is waiting to be set up in your server. If you''re not sure where to start, `/storyadmin setup` will walk you through it. If you have any questions, you''re welcome to drop by the Hub server where I''ll be happy to help directly: [hubInviteUrl]. Thanks for trying my bot!\n~Shantismurf', 'en', 1),
('txtOnboardingDay14', 'Hey, this will be the last check-in about Round Robin StoryBot. It has been two weeks since the bot was installed, but not configured in your server. To keep the system clean, unconfigured servers will be removed after 30 days, in about two more weeks. If you''d like to keep the bot installed, `/storyadmin setup` will only take a minute to complete, or reach out in the Hub server if you need a hand: [hubInviteUrl].\n~Shantismurf', 'en', 1),
('txtOnboardingDay30Removal', 'Round Robin StoryBot will now be removed from your server. The Hub server is always available if you have questions: [hubInviteUrl]. Thanks for giving it a look!', 'en', 1);
